function solve(n) {
    // Helper function to reverse an integer
    const reverseInteger = (num) => {
        return parseInt(String(num).split('').reverse().join(''));
    };

    const r = reverseInteger(n);

    const start = Math.min(n, r);
    const end = Math.max(n, r);

    // Sieve of Eratosthenes to find primes up to 'end' (max is 1000)
    const maxVal = end;
    const isPrime = new Array(maxVal + 1).fill(true);
    isPrime[0] = isPrime[1] = false;

    for (let p = 2; p * p <= maxVal; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i <= maxVal; i += p)
                isPrime[i] = false;
        }
    }

    let sumOfPrimes = 0;

    // Sum primes in the range [start, end]
    for (let i = start; i <= end; i++) {
        if (isPrime[i]) {
            sumOfPrimes += i;
        }
    }

    return sumOfPrimes;
}

